noncompliant:
// Repeated unary operators
int i = 1;
int j = - - -i;  // Noncompliant: equivalent to "-i"
int k = ~~i;     // Noncompliant: equivalent to "i"

bool b = false;
bool c = !!!b;   // Noncompliant: equivalent to "!b"

// Repeated increment/decrement
int x = 5;
int y = ++ ++x;  // Noncompliant
int z = ----x;   // Noncompliant

compliant:
// Single unary operators
int i = 1;
int j = -i;      // Single minus
int k = ~i;      // Single bitwise NOT

bool b = false;
bool c = !b;     // Single logical NOT

// Use compound assignment for clarity
int x = 5;
x += 2;          // Clear increment by 2
int y = x;
x -= 2;          // Clear decrement by 2
int z = x;
